import{_ as a,o as t,c as o,ag as h}from"./chunks/framework.BZohXCq9.js";const g=JSON.parse('{"title":"Hướng dẫn Tích hợp Bên thứ ba (3rd Party Integrations)","description":"","frontmatter":{},"headers":[],"relativePath":"99-tham-khao/archive/01-nen-tang-he-thong/07-tich-hop-ben-thu-ba.md","filePath":"99-tham-khao/archive/01-nen-tang-he-thong/07-tich-hop-ben-thu-ba.md"}'),e={name:"99-tham-khao/archive/01-nen-tang-he-thong/07-tich-hop-ben-thu-ba.md"};function i(r,n,l,d,c,u){return t(),o("div",null,[...n[0]||(n[0]=[h('<h1 id="huong-dan-tich-hop-ben-thu-ba-3rd-party-integrations" tabindex="-1">Hướng dẫn Tích hợp Bên thứ ba (3rd Party Integrations) <a class="header-anchor" href="#huong-dan-tich-hop-ben-thu-ba-3rd-party-integrations" aria-label="Permalink to &quot;Hướng dẫn Tích hợp Bên thứ ba (3rd Party Integrations)&quot;">​</a></h1><p>Tài liệu đặc tả cấu hình và luồng tích hợp với các dịch vụ ngoại vi cho Vivu Travel.</p><h2 id="_1-luu-tru-hinh-anh-cloudinary" tabindex="-1">1. Lưu trữ Hình ảnh (Cloudinary) <a class="header-anchor" href="#_1-luu-tru-hinh-anh-cloudinary" aria-label="Permalink to &quot;1. Lưu trữ Hình ảnh (Cloudinary)&quot;">​</a></h2><p>Hệ thống sử dụng Cloudinary để lưu trữ và tối ưu hóa hình ảnh.</p><h3 id="cau-hinh" tabindex="-1">Cấu hình: <a class="header-anchor" href="#cau-hinh" aria-label="Permalink to &quot;Cấu hình:&quot;">​</a></h3><ul><li><strong>Cloud Name</strong>: (Lấy từ env)</li><li><strong>Upload Preset</strong>: <code>vivu_travel_preset</code></li><li><strong>Folder Structure</strong>: <ul><li><code>destinations/</code>: Chứa ảnh các địa điểm.</li><li><code>tours/</code>: Chứa ảnh các tour du lịch.</li><li><code>profiles/</code>: Chứa ảnh đại diện người dùng.</li></ul></li></ul><h3 id="quy-trinh" tabindex="-1">Quy trình: <a class="header-anchor" href="#quy-trinh" aria-label="Permalink to &quot;Quy trình:&quot;">​</a></h3><ol><li>Client (Admin/App) gọi <code>Cloudinary Upload API</code> với <code>upload_preset</code>.</li><li>Cloudinary trả về <code>secure_url</code>.</li><li>Lưu <code>secure_url</code> vào database (Bảng Destination/Tour).</li></ol><hr><h2 id="_2-cong-thanh-toan-vnpay-momo" tabindex="-1">2. Cổng Thanh toán (VNPAY / Momo) <a class="header-anchor" href="#_2-cong-thanh-toan-vnpay-momo" aria-label="Permalink to &quot;2. Cổng Thanh toán (VNPAY / Momo)&quot;">​</a></h2><p>Tích hợp cổng thanh toán trong Sprint 4.</p><h3 id="luong-thanh-toan-payment-flow" tabindex="-1">Luồng Thanh toán (Payment Flow): <a class="header-anchor" href="#luong-thanh-toan-payment-flow" aria-label="Permalink to &quot;Luồng Thanh toán (Payment Flow):&quot;">​</a></h3><ol><li><strong>Khởi tạo</strong>: User nhấn thanh toán -&gt; Backend tạo đơn hàng <code>PENDING</code> -&gt; Gọi API VNPAY tạo link thanh toán.</li><li><strong>Redirect</strong>: Redirect người dùng sang trang VNPAY.</li><li><strong>Phản hồi (IPN/Webhook)</strong>: VNPAY gửi tín hiệu kết quả về API <code>/api/payment/vnpay-return</code>.</li><li><strong>Xử lý</strong>: <ul><li>Nếu thành công: Cập nhật <code>Booking.status = PAID</code> -&gt; Gửi Email xác nhận.</li><li>Nếu thất bại: Hiển thị lỗi -&gt; Cho phép User thử lại.</li></ul></li></ol><hr><h2 id="_3-ban-đo-đia-điem-google-maps-sdk" tabindex="-1">3. Bản đồ &amp; Địa điểm (Google Maps SDK) <a class="header-anchor" href="#_3-ban-đo-đia-điem-google-maps-sdk" aria-label="Permalink to &quot;3. Bản đồ &amp; Địa điểm (Google Maps SDK)&quot;">​</a></h2><h3 id="tinh-nang" tabindex="-1">Tính năng: <a class="header-anchor" href="#tinh-nang" aria-label="Permalink to &quot;Tính năng:&quot;">​</a></h3><ul><li><strong>Web</strong>: Sử dụng <code>Google Maps Embed API</code> để hiển thị vị trí Tour/Destination.</li><li><strong>Mobile</strong>: Sử dụng <code>react-native-maps</code> để hiển thị bản đồ tương tác.</li></ul><h3 id="cau-hinh-1" tabindex="-1">Cấu hình: <a class="header-anchor" href="#cau-hinh-1" aria-label="Permalink to &quot;Cấu hình:&quot;">​</a></h3><ul><li>Cần đăng ký <code>API Key</code> trên Google Cloud Console.</li><li>Giới hạn (Restrict) API Key theo tên miền (Web) và App ID (Mobile/Android/iOS).</li></ul><hr><p><em>Tài liệu kỹ thuật v1.0</em></p>',21)])])}const p=a(e,[["render",i]]);export{g as __pageData,p as default};
